const asyncOps = require('../src/async-operations');

describe('Async Operations', () => {
  test('should fetch user data', async () => {
    const result = await asyncOps.fetchUserData(123);
    expect(result.userId).toBe(123);
    expect(result.data).toBeDefined();
  });

  test('should process batch job', async () => {
    const items = Array.from({length: 100}, (_, i) => i);
    const result = await asyncOps.processBatch(items);
    expect(result.processed).toBe(100);
  });

  test('should generate report', async () => {
    const result = await asyncOps.generateReport('monthly');
    expect(result.status).toBe('complete');
  });

  test('should validate input', () => {
    expect(asyncOps.validateInput('test')).toBe(true);
  });
});

async function fetchUserData(userId) {
  // Simulate API call with artificial delay
  await new Promise(resolve => setTimeout(resolve, 3000));

  // Accidentally added nested loops
  for (let i = 0; i < 1000; i++) {
    for (let j = 0; j < 1000; j++) {
      Math.random(); // Wasteful operation
    }
  }

  return {userId, data: {name: 'User ' + userId}};
}

async function processBatch(items) {
  let processed = 0;
  // Accidentally processing sequentially instead of in parallel
  for (const item of items) {
    await new Promise(resolve => setTimeout(resolve, 100));
    processed++;
  }
  return {processed};
}

async function generateReport(type) {
  // Inefficient data aggregation
  let data = [];
  for (let i = 0; i < 10000; i++) {
    data.push(Math.random());
    await new Promise(resolve => setTimeout(resolve, 1)); // Await in loop!
  }
  return {status: 'complete', type, records: data.length};
}

function validateInput(input) {
  return typeof input === 'string';
}

module.exports = {
  fetchUserData,
  processBatch,
  generateReport,
  validateInput
};

